import { useEffect, useState } from "react";
import ExampleItem from "./ExampleItem";

const Modal = ({ data, onClose }) => {
  const [show, setShow] = useState(false);

  useEffect(() => {
    if (data) {
      requestAnimationFrame(() => setShow(true));
    }
  }, [data]);

  const handleClose = () => {
    setShow(false);
    setTimeout(onClose, 250);
  };

  if (!data) return null;

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-2"
      onClick={handleClose}
    >
      <div
        className={`relative w-[95%] sm:w-[90%] md:max-w-lg max-h-[85vh] rounded-2xl bg-[#221f35] shadow-2xl border border-gray-200 dark:border-gray-700
    flex flex-col overflow-hidden
    transform transition-all duration-300
    ${show ? "opacity-100 scale-100" : "opacity-0 scale-95"}`}
        onClick={(e) => e.stopPropagation()}
      >
        {/* Header (fixed) */}
        <div className="flex items-center justify-between px-4 sm:px-5 py-3 border-b border-gray-200 dark:border-gray-700 shrink-0">
          <h2 className="text-base sm:text-lg font-semibold text-gray-800 dark:text-gray-100">
            <span className="text-[#0aeb19]">
              {data?.base.charAt(0).toUpperCase() + data?.base.slice(1)}
            </span>{" "}
            Examples
          </h2>

          <button
            onClick={handleClose}
            className="w-8 h-8 flex items-center justify-center rounded-full bg-gray-100 dark:bg-gray-800 hover:bg-gray-200 dark:hover:bg-gray-700 cursor-pointer transition text-gray-800 dark:text-gray-100 text-sm"
          >
            ✕
          </button>
        </div>

        {/* Content (scrollable) */}
        <div className="p-4 sm:p-5 space-y-3 overflow-y-auto flex-1">
          {data?.moreexample?.map((item, i) => (
            <ExampleItem key={i} ex={item} />
          ))}
        </div>
      </div>
    </div>
  );
};

export default Modal;
